<template>
  <div class="bg-white rounded-[2rem] border border-slate-100 p-8 md:p-10 animate-scale-in max-w-md mx-auto shadow-sm">
    <h2 class="text-2xl font-heading font-bold text-slate-900 text-center mb-2">Create Vendor Account</h2>
    <p class="text-slate-500 text-center mb-8">Join CurateWithNG and start selling to thousands of shoppers</p>

    <form @submit.prevent="handleRegister" class="space-y-4">
      <div class="grid grid-cols-2 gap-4">
        <div>
          <label class="text-sm font-medium text-slate-700 mb-1 block">First Name</label>
          <input v-model="form.firstName" type="text" required class="input-field" placeholder="Jane" />
        </div>
        <div>
          <label class="text-sm font-medium text-slate-700 mb-1 block">Last Name</label>
          <input v-model="form.lastName" type="text" required class="input-field" placeholder="Doe" />
        </div>
      </div>
      <div>
        <label class="text-sm font-medium text-slate-700 mb-1 block">Business/Brand Name</label>
        <input v-model="form.businessName" type="text" required class="input-field" placeholder="Jane's Hampers" />
      </div>
      <div>
        <label class="text-sm font-medium text-slate-700 mb-1 block">Email</label>
        <input v-model="form.email" type="email" required class="input-field" placeholder="you@example.com" />
      </div>
      <div>
        <label class="text-sm font-medium text-slate-700 mb-1 block">Phone (optional)</label>
        <input v-model="form.phone" type="tel" class="input-field" placeholder="801 234 5678" />
      </div>
      <div>
        <label class="text-sm font-medium text-slate-700 mb-1 block">Password</label>
        <input v-model="form.password" type="password" required minlength="8" title="Password must be at least 8 characters long" class="input-field" placeholder="At least 8 characters" />
      </div>
      <button type="submit" :disabled="loading" class="btn-primary w-full flex items-center justify-center gap-2 py-2.5">
        <Loader2 v-if="loading" class="w-5 h-5 animate-spin" />
        {{ loading ? 'Creating account...' : 'Create Account' }}
      </button>
    </form>

    <div class="mt-6">
      <div class="relative">
        <div class="absolute inset-0 flex items-center"><div class="w-full border-t border-slate-200"></div></div>
        <div class="relative flex justify-center text-sm"><span class="px-2 bg-white text-slate-400">Or</span></div>
      </div>
      <button @click="handleGoogleLogin" type="button" class="mt-4 flex items-center justify-center gap-3 w-full py-3 px-4 border-2 border-slate-200 rounded-xl text-slate-700 font-medium hover:bg-slate-50 transition-colors">
        <svg class="w-5 h-5" viewBox="0 0 24 24"><path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 01-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z" fill="#4285F4"/><path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/><path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/><path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/></svg>
        Sign up with Google
      </button>
    </div>

    <p class="text-center text-sm text-slate-500 mt-6">
      Already have a vendor account? <NuxtLink to="/auth/login" class="text-primary-800 font-semibold hover:underline">Sign in</NuxtLink>
    </p>
  </div>
</template>

<script setup lang="ts">
import { Loader2 } from 'lucide-vue-next';
import { reactive, ref } from 'vue';

definePageMeta({ layout: 'auth' });
useHead({ title: 'Create Vendor Account — CurateWithNG' });

import { useAuth } from '~/composables/modules/auth/useAuth';

const { register, firebaseGoogleLogin } = useAuth();
const loading = ref(false);

const form = reactive({
  firstName: '',
  lastName: '',
  businessName: '',
  email: '',
  phone: '',
  password: '',
});

const handleRegister = async () => {
  loading.value = true;
  try {
    await register(form);
    navigateTo('/dashboard');
  } catch (e: any) {
    alert(e.data?.message || e.message || 'Registration failed. Please try again.');
  } finally {
    loading.value = false;
  }
};

const handleGoogleLogin = async () => {
  loading.value = true;
  try {
    const { $firebaseAuth } = useNuxtApp();
    const { GoogleAuthProvider, signInWithPopup } = await import('firebase/auth');
    const provider = new GoogleAuthProvider();
    
    const result = await signInWithPopup($firebaseAuth, provider);
    const idToken = await result.user.getIdToken();
    
    await firebaseGoogleLogin({ token: idToken });
    navigateTo('/dashboard');
  } catch (e: any) {
    alert(e.data?.message || e.message || 'Google Login failed');
  } finally {
    loading.value = false;
  }
};
</script>
